import React, { useState, useEffect } from 'react';
import { portfolioAPI } from '../../api';
import { Plus, Pencil as Edit2, Trash2, Save, X, Loader2, GraduationCap, Calendar, MapPin, Award } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const EducationManager = () => {
  const [data, setData] = useState([]);
  const initialForm = { degree: '', institution: '', location: '', duration: '', result: '', description: '', order: 0 };
  const [formData, setFormData] = useState(initialForm);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const { data } = await portfolioAPI.getEducation();
      setData(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await portfolioAPI.updateEducation(editingId, formData);
      } else {
        await portfolioAPI.addEducation(formData);
      }
      fetchData();
      setShowModal(false);
      setFormData(initialForm);
      setEditingId(null);
    } catch (err) {
      console.error(err);
    }
  };

  const handleEdit = (item) => {
    setFormData(item);
    setEditingId(item._id);
    setShowModal(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this entry?')) {
      try {
        await portfolioAPI.deleteEducation(id);
        fetchData();
      } catch (err) {
        console.error(err);
      }
    }
  };

  if (loading && data.length === 0) return <div className="flex justify-center p-20"><Loader2 className="animate-spin text-sky-600" size={40} /></div>;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white p-5 rounded border border-slate-100 shadow-sm">
        <div>
          <h3 className="text-lg font-black text-slate-900">Education Management</h3>
          <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1">Manage your academic background</p>
        </div>
        <button 
          onClick={() => { setEditingId(null); setFormData(initialForm); setShowModal(true); }}
          className="flex items-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded font-black text-[11px] uppercase tracking-widest hover:bg-sky-600 transition-all shadow-lg"
        >
          <Plus size={16} /> Add Education
        </button>
      </div>

      <div className="bg-white rounded border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Degree & Institution</th>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Result & Location</th>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Duration</th>
              <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {data.map((item) => (
              <tr key={item._id} className="hover:bg-slate-50/50 transition-colors group">
                <td className="px-6 py-4">
                  <div className="font-bold text-slate-900 text-[13px]">{item.degree}</div>
                  <div className="text-[11px] text-slate-500 font-medium">{item.institution}</div>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2 text-sky-600 text-[10px] font-black uppercase mb-1"><Award size={12} /> {item.result || 'N/A'}</div>
                  <div className="text-[11px] text-slate-400 flex items-center gap-1 font-medium"><MapPin size={12} /> {item.location}</div>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2 text-slate-500 text-[11px] font-bold">
                    <Calendar size={14} className="text-slate-300" /> {item.duration}
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => handleEdit(item)} className="p-2 text-slate-400 hover:text-sky-600 hover:bg-sky-50 rounded transition-all"><Edit2 size={16} /></button>
                    <button onClick={() => handleDelete(item._id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded transition-all"><Trash2 size={16} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <AnimatePresence>
        {showModal && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <motion.div 
              initial={{ opacity: 0, scale: 0.95, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95, y: 20 }}
              className="relative w-full max-w-lg bg-white rounded shadow-2xl overflow-hidden flex flex-col max-h-[85vh] m-4"
            >
              <div className="flex items-center justify-between p-5 border-b border-slate-100 flex-shrink-0 bg-white">
                <h4 className="text-base font-black text-slate-900">{editingId ? 'Edit Education' : 'Add Education'}</h4>
                <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-900 p-1"><X size={18} /></button>
              </div>

              <form onSubmit={handleSubmit} className="p-6 overflow-y-auto custom-scrollbar flex-1 bg-white">
                <div className="grid md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Degree Name</label>
                    <input required value={formData.degree} onChange={(e) => setFormData({...formData, degree: e.target.value})} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded outline-none text-[13px] font-medium focus:bg-white focus:border-sky-500" placeholder="e.g. BSc in CSE" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Institution</label>
