import { useState, useEffect } from 'react';
import { messageAPI, notifyAPI } from '../../api';
import { Trash2, Loader2, MessageSquare, Mail, Calendar, CheckCircle } from 'lucide-react';

const MessageManager = ({ fetchNotifications }) => {
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMessages();
    markAsRead();
  }, []);

  const fetchMessages = async () => {
    try {
      const { data } = await messageAPI.getContacts();
      setMessages(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const markAsRead = async () => {
    try {
      await notifyAPI.markRead('messages');
      if (fetchNotifications) fetchNotifications();
    } catch (err) {
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure?')) {
      try {
        await messageAPI.deleteContact(id);
        fetchMessages();
      } catch (err) {
        alert('Failed to delete');
      }
    }
  };

  if (loading && messages.length === 0) return <div className="flex justify-center p-20"><Loader2 className="animate-spin text-sky-600" size={40} /></div>;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h3 className="text-lg font-black text-slate-900">Contact Inquiries</h3>
          <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-1">{messages.length} Messages total</p>
        </div>
        <div className="flex items-center gap-2 text-emerald-500 bg-emerald-50 px-3 py-1.5 rounded text-[10px] font-black uppercase tracking-widest">
           <CheckCircle size={14} /> All Read
        </div>
      </div>

      <div className="bg-white rounded border border-slate-100 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Sender</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Message</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Date</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {messages.map((msg) => (
                <tr key={msg._id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-[13px] font-bold text-slate-900">{msg.name}</span>
                      <span className="text-[11px] text-slate-400 flex items-center gap-1"><Mail size={10} /> {msg.email}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 max-w-xs">
                    <div className="flex flex-col">
                      <span className="text-[11px] font-black text-slate-900 uppercase tracking-tight truncate">{msg.subject}</span>
                      <p className="text-[11px] text-slate-500 line-clamp-1">{msg.message}</p>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="text-[10px] font-bold text-slate-400 flex items-center gap-1"><Calendar size={12} /> {new Date(msg.createdAt).toLocaleDateString()}</span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => handleDelete(msg._id)} className="p-2 text-red-500 hover:bg-red-50 rounded transition-all"><Trash2 size={16} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default MessageManager;

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Layers, Briefcase, MessageSquare, UserPlus, TrendingUp, Clock, ArrowUpRight, Settings } from 'lucide-react';
import { portfolioAPI, messageAPI } from '../../api';

const Overview = () => {
  const [stats, setStats] = useState({
    projects: 0,
    experience: 0,
    messages: 0,
    proposals: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [projects, experience, messages, proposals, skills] = await Promise.all([
          portfolioAPI.getProjects(),
          portfolioAPI.getExperience(),
          messageAPI.getContacts(),
          messageAPI.getProposals(),
          portfolioAPI.getSkills()
        ]);
        
        setStats({
          projects: projects.data.length,
          experience: experience.data.length,
          messages: messages.data.length,
          proposals: proposals.data.length,
          skills: skills.data.length
        });
      } catch (err) {
        console.error("Failed to fetch stats", err);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  const cards = [
    { title: 'Total Projects', value: stats.projects, icon: Layers, color: 'text-sky-600', bg: 'bg-sky-50' },
    { title: 'Technical Skills', value: stats.skills, icon: ArrowUpRight, color: 'text-violet-600', bg: 'bg-violet-50' },
    { title: 'New Inquiries', value: stats.messages, icon: MessageSquare, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { title: 'Job Proposals', value: stats.proposals, icon: UserPlus, color: 'text-amber-600', bg: 'bg-amber-50' },
  ];

  if (loading) return <div className="animate-pulse space-y-8">
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
      {[1,2,3,4].map(i => <div key={i} className="h-32 bg-white rounded-[2rem] border border-slate-100" />)}
    </div>
  </div>;

  return (
    <div className="space-y-6">
      {/* Welcome Section */}
      <section className="relative overflow-hidden bg-slate-900 rounded p-8 md:p-10 text-white">
        <div className="relative z-10 max-w-xl">
          <h2 className="text-2xl md:text-3xl font-black tracking-tighter mb-2">Welcome back, Mehedi!</h2>
          <p className="text-slate-400 font-medium text-xs md:text-sm leading-relaxed">
            Your portfolio is performing well. You have {stats.messages} inquiries waiting.
          </p>
        </div>
        <div className="absolute top-0 right-0 p-8 opacity-5">
          <TrendingUp size={120} />
        </div>
      </section>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {cards.map((card, i) => (
          <motion.div
            key={i}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.05 }}
            className="bg-white p-5 rounded border border-slate-100 shadow-sm group hover:shadow-md transition-all"
          >
            <div className={`w-10 h-10 ${card.bg} ${card.color} rounded flex items-center justify-center mb-4 group-hover:scale-105 transition-transform`}>
              <card.icon size={20} />
            </div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">{card.title}</p>
            <h4 className="text-xl font-black text-slate-900">{card.value}</h4>
          </motion.div>
        ))}
      </div>

      {/* Quick Actions / Recent Activity Placeholder */}
      <div className="grid lg:grid-cols-3 gap-6">
         <div className="lg:col-span-2 bg-white p-6 rounded border border-slate-100">
            <div className="flex items-center justify-between mb-6">
               <h3 className="text-sm font-black text-slate-900">System Status</h3>
               <span className="flex items-center gap-1.5 text-[9px] font-black text-emerald-500 uppercase tracking-widest bg-emerald-50 px-2 py-0.5 rounded-full">
                  <span className="w-1 h-1 bg-emerald-500 rounded-full animate-ping" /> Live
               </span>
            </div>
            <div className="space-y-3">
